const results = $input.first().json.results || [];
const recipeName = $('Pick Recipe').first().json.recipe_name;

if (!results.length) throw new Error('No photos found for: ' + recipeName);

const imageUrl = results[0].urls.regular.split('?')[0] + '?w=1200&q=80';

return [{ json: { recipe_name: recipeName, image_url: imageUrl } }];

const raw = $input.first().json.text;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'en' } }];

const raw = $input.first().json.text;

let content = raw
  .replace(/^```(?:markdown|md)?\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

const filenameMatch = content.match(/<!--\s*filename:\s*([\w-]+\.md)\s*-->/);
const filename = filenameMatch ? filenameMatch[1] : 'recipe-' + Date.now() + '.md';

const cleanContent = content
  .replace(/<!--\s*filename:[^>]+-->\n?/, '')
  .trim();

return [{ json: { filename, content: cleanContent, lang: 'es' } }];

const items = $input.all();
const en = items.find(i => i.json.lang === 'en');
const es = items.find(i => i.json.lang === 'es');

if (!en || !es) {
  throw new Error('Missing language variant. Got: ' + JSON.stringify(items.map(i => i.json.lang)));
}

const recipeName = en.json.filename.replace('.md', '');

return [{
  json: {
    en_filename: en.json.filename,
    en_content: en.json.content,
    es_filename: es.json.filename,
    es_content: es.json.content,
    commit_message: 'feat: add ' + recipeName + ' recipe (EN + ES)'
  }
}];

const prepareData = $input.first().json;

function addDraft(content) {
  return content.replace(/^---\n/, '---\ndraft: true\n');
}

const slug = prepareData.en_filename.replace('.md', '');

return [{
  json: {
    en_filename: prepareData.en_filename,
    en_content: addDraft(prepareData.en_content),
    es_filename: prepareData.es_filename,
    es_content: addDraft(prepareData.es_content),
    commit_message: prepareData.commit_message,
    recipe_slug: slug
  }
}];

const draftData = $('Inject Draft Frontmatter').first().json;
const branchInfo = $input.first().json;
// GET /branches/{branch} returns: { commit: { sha, commit: { tree: { sha } } } }
const parentCommitSha = branchInfo.commit.sha;
const currentTreeSha = branchInfo.commit.commit.tree.sha;

return [{
  json: {
    body: {
      base_tree: currentTreeSha,
      tree: [
        {
          path: 'recipes/en/' + draftData.en_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.en_content
        },
        {
          path: 'recipes/es/' + draftData.es_filename,
          mode: '100644',
          type: 'blob',
          content: draftData.es_content
        }
      ]
    },
    parent_commit_sha: parentCommitSha,
    commit_message: draftData.commit_message,
    default_branch: 'drafts'
  }
}];

const newTreeSha = $input.first().json.sha;
const parentSha = $('Build Create Tree Request').first().json.parent_commit_sha;
const message = $('Build Create Tree Request').first().json.commit_message;

return [{
  json: {
    body: {
      message: message,
      tree: newTreeSha,
      parents: [parentSha]
    }
  }
}];

const enFilename = $('Prepare Commit').first().json.en_filename;
const slug = enFilename.replace(/\.md$/i, '');
const base = (process.env.VERCEL_PREVIEW_BASE_URL || 'https://lowkeycooking-blog-git-drafts-christophcharafs-projects.vercel.app').replace(/\/$/, '');
const previewUrl = base + '/en/recipes/' + slug;
const recipeName = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
return [{ json: { previewUrl, slug, recipeName } }];

const data = $('Build Preview URL').first().json;
const previewUrl = data.previewUrl;
const maxAttempts = Math.max(1, parseInt(process.env.PREVIEW_POLL_MAX_ATTEMPTS || '40', 10) || 40);
const delayMs = Math.max(1000, parseInt(process.env.PREVIEW_POLL_INTERVAL_MS || '15000', 10) || 15000);

for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  let statusCode = 0;
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: previewUrl,
      returnFullResponse: true,
      timeout: 60000,
    });
    statusCode = typeof res.statusCode === 'number' ? res.statusCode : 0;
  } catch (error) {
    statusCode = error.response?.status ?? error.status ?? 0;
  }

  if (statusCode >= 200 && statusCode < 400) {
    return [{ json: { ...data, previewPollAttempts: attempt } }];
  }

  if (attempt < maxAttempts) {
    await new Promise((resolve) => setTimeout(resolve, delayMs));
  }
}

throw new Error(
  'Preview URL did not become reachable (HTTP 2xx/3xx) after ' +
    maxAttempts +
    ' attempts (~' +
    Math.round((maxAttempts * delayMs) / 60000) +
    ' min): ' +
    previewUrl
);

const data = $('Build Preview URL').first().json;
const text = '<b>🍳 New Recipe Draft: ' + data.recipeName + '</b>

Preview is live — ready for review:
' + data.previewUrl;
return [{ json: { text } }];
